import { Injectable, inject } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { Observable } from 'rxjs';
import { environment } from '../../../environments/environment';
import { Match, Message } from '../models';

/**
 * REST access for matches and their message threads.
 * Mirrors the inline HttpClient pattern used in feed/profile-edit.
 */
@Injectable({ providedIn: 'root' })
export class MatchService {
  private http = inject(HttpClient);
  private readonly apiUrl = environment.apiUrl;

  /** GET /api/matches — matches for the authenticated user. */
  list(): Observable<Match[]> {
    return this.http.get<Match[]>(`${this.apiUrl}/matches`);
  }

  /** GET /api/matches/:id/messages — full thread, oldest first. */
  messages(matchId: string): Observable<Message[]> {
    return this.http.get<Message[]>(`${this.apiUrl}/matches/${matchId}/messages`);
  }

  /** POST /api/matches/:id/messages — persist a message; response has `mine: true`. */
  send(matchId: string, body: string): Observable<Message> {
    return this.http.post<Message>(`${this.apiUrl}/matches/${matchId}/messages`, { body });
  }
}
